// SPDX-License-Identifier: MIT
pragma solidity ^0.8.27;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

contract VEILTreasury is Ownable, ReentrancyGuard {
    IERC20 public immutable veilToken;

    uint256 public constant TIMELOCK_DELAY = 48 hours;

    struct WithdrawalRequest {
        address recipient;
        uint256 amount;
        uint256 readyAt;
        bool executed;
        bool cancelled;
    }

    mapping(uint256 => WithdrawalRequest) public withdrawalRequests;
    uint256 public nextRequestId;

    event WithdrawalProposed(uint256 indexed requestId, address indexed recipient, uint256 amount, uint256 readyAt);
    event WithdrawalExecuted(uint256 indexed requestId, address indexed recipient, uint256 amount);
    event WithdrawalCancelled(uint256 indexed requestId);
    event TokensReceived(address indexed from, uint256 amount);

    constructor(address initialOwner, address _veilToken) Ownable(initialOwner) {
        veilToken = IERC20(_veilToken);
    }

    /// @notice Propose a withdrawal; it becomes executable after TIMELOCK_DELAY.
    function proposeWithdrawal(address recipient, uint256 amount) external onlyOwner returns (uint256 requestId) {
        require(recipient != address(0), "VeilTreasury: zero recipient");
        require(amount > 0, "VeilTreasury: zero amount");
        require(veilToken.balanceOf(address(this)) >= amount, "VeilTreasury: insufficient balance");

        requestId = nextRequestId++;
        uint256 readyAt = block.timestamp + TIMELOCK_DELAY;

        withdrawalRequests[requestId] = WithdrawalRequest({
            recipient: recipient,
            amount: amount,
            readyAt: readyAt,
            executed: false,
            cancelled: false
        });

        emit WithdrawalProposed(requestId, recipient, amount, readyAt);
    }

    /// @notice Execute a previously proposed withdrawal once the timelock has passed.
    function executeWithdrawal(uint256 requestId) external onlyOwner nonReentrant {
        WithdrawalRequest storage req = withdrawalRequests[requestId];
        require(!req.executed, "VeilTreasury: already executed");
        require(!req.cancelled, "VeilTreasury: cancelled");
        require(block.timestamp >= req.readyAt, "VeilTreasury: timelock active");

        req.executed = true;
        require(veilToken.transfer(req.recipient, req.amount), "VeilTreasury: transfer failed");

        emit WithdrawalExecuted(requestId, req.recipient, req.amount);
    }

    /// @notice Cancel a pending withdrawal before it executes.
    function cancelWithdrawal(uint256 requestId) external onlyOwner {
        WithdrawalRequest storage req = withdrawalRequests[requestId];
        require(!req.executed, "VeilTreasury: already executed");
        require(!req.cancelled, "VeilTreasury: already cancelled");

        req.cancelled = true;
        emit WithdrawalCancelled(requestId);
    }

    /// @notice View current VEIL balance held by the treasury.
    function balance() external view returns (uint256) {
        return veilToken.balanceOf(address(this));
    }
}

contracts/VEILVesting.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.27;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

contract VEILVesting is Ownable {
    IERC20 public immutable token;
    address public immutable beneficiary;
    uint256 public immutable amount;
    uint256 public immutable startTime;
    uint256 public immutable cliffDuration;
    uint256 public immutable vestingDuration;
    bool public immutable revocable;

    uint256 public released;
    bool public revoked;

    event Released(uint256 amount);
    event Revoked();

    constructor(
        address initialOwner,
        address _token,
        address _beneficiary,
        uint256 _amount,
        uint256 _startTime,
        uint256 _cliffDuration,
        uint256 _vestingDuration,
        bool _revocable
    ) Ownable(initialOwner) {
        require(_beneficiary != address(0), "VEILVesting: zero beneficiary");
        require(_vestingDuration > 0, "VEILVesting: zero duration");
        require(_amount > 0, "VEILVesting: zero amount");
        token = IERC20(_token);
        beneficiary = _beneficiary;
        amount = _amount;
        startTime = _startTime;
        cliffDuration = _cliffDuration;
        vestingDuration = _vestingDuration;
        revocable = _revocable;
    }

    function release() external {
        uint256 releasable = vestedAmount() - released;
        require(releasable > 0, "VEILVesting: nothing to release");
        released += releasable;
        require(token.transfer(beneficiary, releasable), "VEILVesting: transfer failed");
        emit Released(releasable);
    }

    function revoke() external onlyOwner {
        require(revocable, "VEILVesting: not revocable");
        require(!revoked, "VEILVesting: already revoked");
        uint256 releasable = vestedAmount() - released;
        if (releasable > 0) {
            released += releasable;
            require(token.transfer(beneficiary, releasable), "VEILVesting: transfer failed");
        }
        uint256 remainder = token.balanceOf(address(this));
        revoked = true;
        if (remainder > 0) {
            require(token.transfer(owner(), remainder), "VEILVesting: return failed");
        }
        emit Revoked();
    }

    function vestedAmount() public view returns (uint256) {
        if (revoked) return released;
        uint256 cliff = startTime + cliffDuration;
        if (block.timestamp < cliff) return 0;
        if (block.timestamp >= startTime + vestingDuration) return amount;
        return (amount * (block.timestamp - startTime)) / vestingDuration;
    }
}

contracts/x402PQCPayments.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.27;

import "@openzeppelin/contracts/access/Ownable.sol";

contract x402PQCPayments is Ownable {
    struct Payment {
        address payer;
        address recipient;
        uint256 amount;
        uint256 timestamp;
        bytes32 sigHash;
        bytes32 pubKeyHash;
    }

    mapping(bytes32 => Payment) private _payments;

    event PaymentRecorded(
        address indexed payer,
        address indexed recipient,
        uint256 amount,
        bytes32 indexed sigHash
    );

    constructor(address initialOwner) Ownable(initialOwner) {}

    function registerPayment(
        address payer,
        address recipient,
        uint256 amount,
        bytes32 sigHash,
        bytes32 pubKeyHash
    ) external onlyOwner {
        require(payer != address(0), "x402PQCPayments: zero payer");
        require(recipient != address(0), "x402PQCPayments: zero recipient");
        require(amount > 0, "x402PQCPayments: zero amount");
        require(_payments[sigHash].timestamp == 0, "x402PQCPayments: duplicate sigHash");

        _payments[sigHash] = Payment({
            payer: payer,
            recipient: recipient,
            amount: amount,
            timestamp: block.timestamp,
            sigHash: sigHash,
            pubKeyHash: pubKeyHash
        });

        emit PaymentRecorded(payer, recipient, amount, sigHash);
    }

    function verifyPayment(bytes32 sigHash) external view returns (bool) {
        return _payments[sigHash].timestamp != 0;
    }

    function getPayment(bytes32 sigHash) external view returns (Payment memory) {
        return _payments[sigHash];
    }
}

